933: // thresholdsMet returns the set of thresholds that were met independent of grace period
934: func thresholdsMet(thresholds []evictionapi.Threshold, observations signalObservations, enforceMinReclaim bool) []evictionapi.Threshold {
935: 	results := []evictionapi.Threshold{}
936: 	for i := range thresholds {
937: 		threshold := thresholds[i]
938: 		observed, found := observations[threshold.Signal]
939: 		if !found {
940: 			klog.InfoS("Eviction manager: no observation found for eviction signal", "signal", threshold.Signal)
941: 			continue
942: 		}
943: 		// determine if we have met the specified threshold
944: 		thresholdMet := false
945: 		quantity := evictionapi.GetThresholdQuantity(threshold.Value, observed.capacity)
946: 		// if enforceMinReclaim is specified, we compare relative to value - minreclaim
947: 		if enforceMinReclaim && threshold.MinReclaim != nil {
948: 			quantity.Add(*evictionapi.GetThresholdQuantity(*threshold.MinReclaim, observed.capacity))
949: 		}
950: 		thresholdResult := quantity.Cmp(*observed.available)
951: 		switch threshold.Operator {
952: 		case evictionapi.OpLessThan:
953: 			thresholdMet = thresholdResult > 0
954: 		}
955: 		if thresholdMet {
956: 			results = append(results, threshold)
957: 		}
958: 	}
959: 	return results
960: }
